-- Q11 phase 2 — swap every primary-key column default from
-- `cuid()` / `gen_random_uuid()` (v4) to `uuidv7()`.
--
-- Pre-requisite: the pg_uuidv7 extension must be installed (see
-- migration 20260503120000_install_pg_uuidv7).
--
-- Strategy: ALTER COLUMN ... SET DEFAULT for every `id` column whose
-- type is `uuid` or text (cuid). New rows get UUID v7; legacy rows
-- keep their existing string IDs. v7 and v4 share the same UUID
-- textual form so legacy IDs continue to validate against
-- `z.string().uuid()`.
--
-- Generated by introspecting the Prisma schema files. If a new model
-- is added, add an ALTER for it here.

-- Identity / users
ALTER TABLE "User"                       ALTER COLUMN "id" SET DEFAULT uuidv7()::text;
ALTER TABLE "Permission"                 ALTER COLUMN "id" SET DEFAULT uuidv7()::text;
ALTER TABLE "Role"                       ALTER COLUMN "id" SET DEFAULT uuidv7()::text;
ALTER TABLE "UserRoleAssignment"         ALTER COLUMN "id" SET DEFAULT uuidv7()::text;
ALTER TABLE "AccessModifier"             ALTER COLUMN "id" SET DEFAULT uuidv7()::text;
ALTER TABLE "UserConsent"                ALTER COLUMN "id" SET DEFAULT uuidv7()::text;
