-- Sanity check — fail if pg_uuidv7 isn't actually available so we
-- never silently fall back to NULL ids.
DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'pg_uuidv7') THEN
    RAISE EXCEPTION 'pg_uuidv7 extension is required for this migration. Run 20260503120000_install_pg_uuidv7 first.';
  END IF;
END$$;
